command:
mkdir -p space && printf 'metrics:
  - {id: m1, dimension: performance}
' > space/metrics.yaml && printf 'dimensions: {performance: {enabled: true}}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml > out.txt 2>err.txt && ! grep -q '<html' out.txt && ! head -c1 out.txt | grep -q '{' && echo ok 1>&2
